require"Net.NetCore.NetDefines"NetworkQualityAnalyzer={}NetworkQualityAnalyzer.__index=NetworkQualityAnalyzer;function NetworkQualityAnalyzer.new()local self=setmetatable({},NetworkQualityAnalyzer)self.latency_data={}self.current_latency_weight=0.7;self.stability_weight=0.3;return self end;function NetworkQualityAnalyzer:clear()self.latency_data={}end;function NetworkQualityAnalyzer:add_latency_sample(a,b)table.insert(self.latency_data,{a,b})local c=a-30;while#self.latency_data>0 and self.latency_data[1][1]<c do table.remove(self.latency_data,1)end end;function NetworkQualityAnalyzer:calculate_stability_score()if#self.latency_data==0 then return DELAY_INF end;local d=self.latency_data[1][2]local e=self.latency_data[1][2]for f=2,#self.latency_data do local g=self.latency_data[f][2]if g>=d then e=d;d=g elseif g>=e then e=g end end;return e end;function NetworkQualityAnalyzer:get_network_quality()if#self.latency_data==0 then return DELAY_INF end;local h=#self.latency_data;local g=0;local i=0;for f=0,9 do if h-f<1 then break end;local j=1.0/(f+1)g=g+self.latency_data[h-f][2]*j;i=i+j end;local k=g/i;local l=self:calculate_stability_score()local m=(k*self.current_latency_weight+l*self.stability_weight)/(self.current_latency_weight+self.stability_weight)return m end;return NetworkQualityAnalyzer